html:
{% set order = frappe.get_doc("Laundry Order", doc.laundry_order) %}
{% set customer = frappe.get_doc("Laundry Customer", order.customer) %}
{% set service_doc = frappe.get_doc("Laundry Service", order.service) %}
<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<style>
  @page { size: 80mm auto; margin: 3mm 4mm; }
  * { box-sizing: border-box; }
  body { font-family: 'Courier New', monospace; color: #000; font-size: 12px; width: 72mm; }
  .center { text-align: center; }
  .lot-number { font-size: 52px; font-weight: 900; text-align: center; letter-spacing: -3px; line-height: 0.9; margin: 3mm 0 2mm; font-family: Arial Black, sans-serif; }
  .machine-line { font-size: 15px; font-weight: bold; text-align: center; margin-bottom: 2mm; }
  .dash { border: none; border-top: 2px dashed #000; margin: 2mm 0; }
  .dot { border: none; border-top: 1px dotted #000; margin: 1.5mm 0; }
  .row { display: flex; justify-content: space-between; align-items: center; margin: 1mm 0; font-size: 11px; }
  .row .lbl { color: #555; font-size: 10px; }
  .tier-badge { border: 1.5px solid #000; padding: 1px 5px; font-size: 10px; font-weight: bold; letter-spacing: 0.5px; }
  .tier-Gold, .tier-Diamond { border-width: 2px; }
  .section-tags { margin: 2mm 0; }
  .tag-chip { display: inline-block; border: 1.5px solid #000; padding: 2px 6px; font-size: 10px; font-weight: bold; margin: 1px 2px 1px 0; }
  .instructions { font-size: 10px; font-style: italic; padding-top: 1.5mm; }
  .footer-row { display: flex; justify-content: space-between; font-size: 9px; color: #777; }
  .shop-name { font-size: 13px; font-weight: bold; letter-spacing: 1px; text-align: center; margin-bottom: 1mm; }
</style>
</head>
<body>

<div class="shop-name">🧺 SPINLY</div>
<div class="lot-number">{{ doc.lot_number or order.lot_number }}</div>
<div class="machine-line">
  {% if doc.assigned_machine %}
    {{ frappe.db.get_value("Laundry Machine", doc.assigned_machine, "machine_name") | upper }}
  {% else %}
    &#8212; UNASSIGNED &#8212;
  {% endif %}
</div>

<hr class="dash">

<div class="row">
  <span><strong>{{ customer.full_name }}</strong></span>
  <span class="tier-badge tier-{{ doc.customer_tier_badge or 'Bronze' }}">{{ (doc.customer_tier_badge or 'Bronze') | upper }}</span>
</div>
<div class="row">
  <span class="lbl">Phone</span>
  <span>{{ customer.phone }}</span>
</div>
<div class="row">
  <span class="lbl">Service</span>
  <span>{{ service_doc.service_name }}</span>
</div>
<div class="row">
  <span class="lbl">Weight</span>
  <span>{{ order.total_weight_kg }} kg</span>
</div>
<div class="row">
  <span class="lbl">ETA</span>
  <span>{% if order.expected_ready_date %}{{ frappe.format(order.expected_ready_date, "Datetime") }}{% else %}TBD{% endif %}</span>
</div>

{% if order.alert_tags %}
<hr class="dash">
<div class="section-tags">
  {% for row in order.alert_tags %}
    {% set tag = frappe.get_doc("Alert Tag", row.alert_tag) %}
    <span class="tag-chip">{{ tag.icon_emoji }} {{ tag.tag_name | upper }}</span>
  {% endfor %}
</div>
{% endif %}

{% if doc.special_instructions %}
<hr class="dot">
<div class="instructions">&#128221; {{ doc.special_instructions }}</div>
{% endif %}

<hr class="dash">
<div class="footer-row">
  <span>{{ doc.name }}</span>
  <span>{{ frappe.format(order.order_date, "Date") }}</span>
</div>

</body>
</html>

{% set customer = frappe.get_doc("Laundry Customer", doc.customer) %}
{% set service_doc = frappe.get_doc("Laundry Service", doc.service) %}
{% set settings = frappe.get_cached_doc("Spinly Settings") %}
{% set sym = settings.currency_symbol or "&#8377;" %}
{% set loyalty = frappe.db.get_value("Loyalty Account", {"customer": doc.customer}, ["current_balance", "tier"], as_dict=True) or {"current_balance": 0, "tier": "Bronze"} %}
{% set pts_earned = ((doc.grand_total or 0) * (settings.loyalty_points_per_rupee or 1)) | int %}
<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<style>
  @page { size: A4; margin: 15mm 18mm; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Arial, sans-serif; color: #1a1a2e; font-size: 12px; line-height: 1.5; }
  /* ── Header ── */
  .header { display: flex; justify-content: space-between; align-items: flex-start; padding-bottom: 8px; border-bottom: 3px solid #3b82f6; margin-bottom: 16px; }
  .brand { font-size: 28px; font-weight: 900; color: #1e40af; letter-spacing: -1px; }
  .brand-sub { font-size: 10px; color: #64748b; letter-spacing: 2px; text-transform: uppercase; margin-top: 2px; }
  .invoice-meta { text-align: right; }
  .invoice-meta .inv-title { font-size: 20px; font-weight: 700; color: #3b82f6; text-transform: uppercase; letter-spacing: 2px; }
  .invoice-meta .inv-num { font-size: 13px; font-weight: bold; color: #1a1a2e; margin-top: 4px; }
  .invoice-meta .inv-date { font-size: 11px; color: #64748b; }
  /* ── Party info ── */
  .parties { display: flex; gap: 16px; margin-bottom: 16px; }
  .party-box { flex: 1; background: #f8fafc; border: 1px solid #e2e8f0; border-radius: 6px; padding: 10px 12px; }
  .party-box .box-label { font-size: 9px; font-weight: bold; letter-spacing: 1.5px; text-transform: uppercase; color: #94a3b8; margin-bottom: 4px; }
  .party-box .name { font-size: 14px; font-weight: 700; color: #1e293b; }
  .party-box .detail { font-size: 11px; color: #475569; margin-top: 2px; }
  .tier-pill { display: inline-block; background: #dbeafe; color: #1d4ed8; padding: 1px 8px; border-radius: 20px; font-size: 10px; font-weight: bold; margin-left: 6px; }
  .tier-pill.Gold { background: #fef9c3; color: #854d0e; }
  .tier-pill.Silver { background: #f1f5f9; color: #475569; }
  .tier-pill.Diamond { background: #ede9fe; color: #5b21b6; }
  /* ── Order Details bar ── */
  .order-bar { background: #1e40af; color: #fff; border-radius: 6px; display: flex; gap: 0; margin-bottom: 16px; overflow: hidden; }
  .order-bar .ob-item { flex: 1; padding: 8px 12px; border-right: 1px solid rgba(255,255,255,0.2); }
  .order-bar .ob-item:last-child { border-right: none; }
  .order-bar .ob-label { font-size: 9px; opacity: 0.7; text-transform: uppercase; letter-spacing: 1px; }
  .order-bar .ob-val { font-size: 13px; font-weight: bold; margin-top: 2px; }
  /* ── Items table ── */
  .section-title { font-size: 10px; font-weight: bold; letter-spacing: 1.5px; text-transform: uppercase; color: #64748b; margin-bottom: 6px; }
  table { width: 100%; border-collapse: collapse; margin-bottom: 14px; }
  thead tr { background: #1e293b; color: #fff; }
  thead th { padding: 7px 10px; text-align: left; font-size: 10px; font-weight: 600; letter-spacing: 0.5px; text-transform: uppercase; }
  thead th:last-child { text-align: right; }
  tbody tr { border-bottom: 1px solid #e2e8f0; }
  tbody tr:nth-child(even) { background: #f8fafc; }
  tbody td { padding: 7px 10px; font-size: 12px; }
  tbody td:last-child { text-align: right; font-weight: 600; }
  tfoot tr td { padding: 5px 10px; font-size: 12px; }
  /* ── Totals ── */
  .totals-wrap { display: flex; justify-content: flex-end; margin-bottom: 16px; }
  .totals-table { width: 200px; }
  .tot-row { display: flex; justify-content: space-between; padding: 4px 0; font-size: 12px; border-bottom: 1px solid #f1f5f9; }
  .tot-row .lbl { color: #64748b; }
  .tot-row.discount .lbl, .tot-row.discount .val { color: #16a34a; font-weight: 600; }
  .tot-grand { display: flex; justify-content: space-between; padding: 8px 10px; background: #1e40af; color: #fff; border-radius: 6px; font-size: 14px; font-weight: 700; margin-top: 6px; }
  /* ── Tags + payment row ── */
  .bottom-row { display: flex; gap: 16px; margin-bottom: 14px; }
  .tags-box { flex: 1; }
  .payment-box { flex: 1; }
  .tag-chip { display: inline-block; padding: 3px 8px; border-radius: 4px; font-size: 10px; font-weight: bold; margin: 2px 3px 2px 0; }
  .payment-status { display: inline-block; padding: 3px 10px; border-radius: 20px; font-size: 11px; font-weight: bold; }
  .status-Paid { background: #dcfce7; color: #15803d; }
  .status-Unpaid { background: #fee2e2; color: #dc2626; }
  .status-Pay-Later { background: #fef9c3; color: #854d0e; }
  /* ── Loyalty strip ── */
  .loyalty-strip { background: linear-gradient(135deg, #1e40af, #7c3aed); color: #fff; border-radius: 8px; padding: 10px 14px; display: flex; justify-content: space-between; align-items: center; margin-bottom: 14px; }
  .ls-left .ls-label { font-size: 9px; opacity: 0.8; text-transform: uppercase; letter-spacing: 1px; }
  .ls-left .ls-pts { font-size: 22px; font-weight: 900; line-height: 1; margin-top: 2px; }
  .ls-right { text-align: right; font-size: 11px; opacity: 0.9; }
  /* ── Footer ── */
  .footer { border-top: 1px solid #e2e8f0; padding-top: 8px; text-align: center; font-size: 9px; color: #94a3b8; letter-spacing: 0.5px; }
  .instructions-box { background: #fffbeb; border: 1px solid #fcd34d; border-radius: 6px; padding: 8px 12px; margin-bottom: 14px; font-size: 11px; color: #92400e; }
</style>
</head>
<body>

<!-- Header -->
<div class="header">
  <div>
    <div class="brand">&#129082; Spinly</div>
    <div class="brand-sub">Premium Laundry &amp; Dry Clean</div>
  </div>
  <div class="invoice-meta">
    <div class="inv-title">Invoice</div>
    <div class="inv-num">{{ doc.name }}</div>
    <div class="inv-date">{{ frappe.format(doc.order_date, "Date") }}</div>
  </div>
</div>

<!-- Parties -->
<div class="parties">
  <div class="party-box">
    <div class="box-label">Bill To</div>
    <div class="name">{{ customer.full_name }}<span class="tier-pill {{ loyalty.tier }}">{{ loyalty.tier }}</span></div>
    <div class="detail">&#128222; {{ customer.phone }}</div>
    <div class="detail" style="margin-top:4px; color:#94a3b8; font-size:10px;">Loyalty Balance: <strong>{{ loyalty.current_balance | int }} pts</strong></div>
  </div>
  <div class="party-box">
    <div class="box-label">Order Info</div>
    <div class="name" style="font-size:13px;">{{ doc.lot_number }}</div>
    <div class="detail">Service: {{ service_doc.service_name }}</div>
    <div class="detail">Ready: {% if doc.expected_ready_date %}{{ frappe.format(doc.expected_ready_date, "Datetime") }}{% else %}TBD{% endif %}</div>
  </div>
</div>

<!-- Order details bar -->
<div class="order-bar">
  <div class="ob-item">
    <div class="ob-label">Machine</div>
    <div class="ob-val">{% if doc.assigned_machine %}{{ frappe.db.get_value("Laundry Machine", doc.assigned_machine, "machine_name") }}{% else %}—{% endif %}</div>
  </div>
  <div class="ob-item">
    <div class="ob-label">Total Weight</div>
    <div class="ob-val">{{ doc.total_weight_kg }} kg</div>
  </div>
  <div class="ob-item">
    <div class="ob-label">Items</div>
    <div class="ob-val">{{ doc.total_items }}</div>
  </div>
  <div class="ob-item">
    <div class="ob-label">Rate / kg</div>
    <div class="ob-val">{{ sym }}{{ service_doc.base_price_per_kg }}</div>
  </div>
</div>

<!-- Items table -->
<div class="section-title">Garment Details</div>
<table>
  <thead>
    <tr>
      <th>Garment</th>
      <th>Qty</th>
      <th>Weight (kg)</th>
      <th>Rate / kg</th>
      <th>Amount</th>
    </tr>
  </thead>
  <tbody>
    {% for row in doc.items %}
    {% set gt = frappe.get_doc("Garment Type", row.garment_type) %}
    <tr>
      <td>{{ gt.icon_emoji }} {{ gt.garment_name }}</td>
      <td>{{ row.quantity }}</td>
      <td>{{ row.weight_kg * row.quantity }}</td>
      <td>{{ sym }}{{ row.unit_price }}</td>
      <td>{{ sym }}{{ "%.2f" | format(row.line_total) }}</td>
    </tr>
    {% endfor %}
  </tbody>
</table>

<!-- Totals -->
<div class="totals-wrap">
  <div class="totals-table">
    <div class="tot-row"><span class="lbl">Subtotal</span><span class="val">{{ sym }}{{ "%.2f" | format(doc.subtotal or 0) }}</span></div>
    {% if doc.discount_amount and doc.discount_amount > 0 %}
    <div class="tot-row discount"><span class="lbl">Loyalty Discount</span><span class="val">&#8722; {{ sym }}{{ "%.2f" | format(doc.discount_amount) }}</span></div>
    {% endif %}
    {% if doc.tax_amount and doc.tax_amount > 0 %}
    <div class="tot-row"><span class="lbl">Tax</span><span class="val">{{ sym }}{{ "%.2f" | format(doc.tax_amount) }}</span></div>
    {% endif %}
    <div class="tot-grand"><span>NET TOTAL</span><span>{{ sym }}{{ "%.2f" | format(doc.grand_total or 0) }}</span></div>
  </div>
</div>

<!-- Tags + Payment -->
<div class="bottom-row">
  {% if doc.alert_tags %}
  <div class="tags-box">
    <div class="section-title">Alert Tags</div>
    {% for row in doc.alert_tags %}
      {% set tag = frappe.get_doc("Alert Tag", row.alert_tag) %}
      <span class="tag-chip" style="background: {{ tag.color_code }}22; color: {{ tag.color_code }}; border: 1px solid {{ tag.color_code }}44;">{{ tag.icon_emoji }} {{ tag.tag_name }}</span>
    {% endfor %}
  </div>
  {% endif %}
  <div class="payment-box">
    <div class="section-title">Payment</div>
    <div style="font-size:13px; font-weight:600; margin-bottom:4px;">{{ doc.payment_method or '—' }}</div>
    <span class="payment-status status-{{ (doc.payment_status or 'Unpaid') | replace(' ', '-') }}">{{ doc.payment_status or 'Unpaid' }}</span>
  </div>
</div>

{% if doc.special_instructions %}
<div class="instructions-box">&#128221; <strong>Instructions:</strong> {{ doc.special_instructions }}</div>
{% endif %}

<!-- Loyalty strip -->
<div class="loyalty-strip">
  <div class="ls-left">
    <div class="ls-label">Points Earned This Visit</div>
    <div class="ls-pts">+{{ pts_earned }} pts</div>
  </div>
  <div class="ls-right">
    <div>Total Balance</div>
    <div style="font-size:18px; font-weight:800;">{{ (loyalty.current_balance + pts_earned) | int }} pts</div>
    <div style="font-size:9px; opacity:0.7; margin-top:2px;">after this order</div>
  </div>
</div>

<!-- Footer -->
<div class="footer">
  Thank you for choosing Spinly &bull; We care for your clothes &bull; {{ doc.name }}
</div>

</body>
</html>
